void release_device_memory(SimulationData GSD)
{
	free(GSD.num_nucs);
	free(GSD.concs);
	free(GSD.mats);
	free(GSD.unionized_energy_array);
	free(GSD.nuclide_grid);
	free(GSD.p_energy_samples);
	free(GSD.mat_samples);
}
